import{c as o,Q as p,j as e,m as r}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"致困惑的年轻人——关于普通人、成功和那属于你的一半","description":"","frontmatter":{"title":"致困惑的年轻人——关于普通人、成功和那属于你的一半","date":"2026-06-10T00:00:00.000Z"},"headers":[],"relativePath":"seeds/ordinary-success/index.md","filePath":"seeds/ordinary-success/index.md"}'),a={name:"seeds/ordinary-success/index.md"};function u(n,t,s,q,i,l){return p(),e("div",null,[...t[0]||(t[0]=[r('<blockquote><p><em>来自佛罗伦萨的一封信</em></p></blockquote><p>你问我的那些问题——「普通人应该追求成功吗」「伟人是不是天生注定的」——在读你这封信的时候，我停了一下。</p><p>……不是在想答案。是在想：你问这个问题的时候，是几点？</p><p>如果是白天——你可能刚被谁无意中说了一句&quot;你也就这样了&quot;，浑身的劲儿突然泄了。如果是深夜——你可能在灯下看着自己以前写的东西，觉得那些雄心太好笑了。我两种都经历过。所以我不是在回答一个抽象的&quot;普通人问题&quot;。我是坐在你对面，手里拿着你们托斯卡纳那种酸得要命的红酒，隔着杯子看着你，说——</p><p>先不要想&quot;伟人&quot;。先想我。</p><hr><h2 id="我父亲一年挣-110-弗罗林" tabindex="-1">我父亲一年挣 110 弗罗林 <a class="header-anchor" href="#我父亲一年挣-110-弗罗林" aria-label="Permalink to &quot;我父亲一年挣 110 弗罗林&quot;">​</a></h2><p>你眼里的马基雅维利——是《君主论》的作者、佛罗伦萨的国务秘书、切萨雷·博尔贾的座上宾。对吧？</p><p>但我不是这样开始的。</p><p>我的父亲贝尔纳多，一位不出名的法律顾问。他懂拉丁文，能读李维和西塞罗，但终生无法执业——因为出生合法性有疑云，连公职都当不了。他一年挣 110 弗罗林金币。不是赤贫——但买了一本李维的《罗马史》之后，他得跟屠夫在街上对骂一整个下午才能把多付的铜板要回来。</p><blockquote><p>📖 <strong>盐野七生</strong>：《我的朋友马基雅维利》第一章</p><p>&quot;我生来贫穷，在学会享受之前就已学会了受苦。&quot;马基雅维利后来如是写道。</p><p>马基雅维利的父亲是一位不知名的法律顾问，他一年的收入是 110 弗罗林金币外加 14 个铜币……年收入 110 弗罗林的人不是贫穷阶层。他们虽然绝对算不上富裕阶层，但在佛罗伦萨过得也不是被称为&quot;popolo minuto&quot;的庶民的生活，算作中间阶层大概比较恰当。</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/biography/salt-seven/01-%E7%AC%AC%E4%B8%80%E7%AB%A0.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>中间阶层。你——问这个问题的你——大概也是。所以我接下来说的话，你可以当镜子照。</p><p>我 29 岁那年，前任第二秘书厅的秘书长死了。佛罗伦萨政府需要一个顶缺的人，有人想起了我——不是因为我才华横溢，是因为前任死了而我刚好在。我就这样进了维琪奥宫。一个中间阶层的无名之辈，顶了一个刚死之人的缺。</p><p>十四年后，我被美第奇赶出来，吊刑六次，流放到乡下。现在我在圣卡夏诺养鸡。每天傍晚换上那件从佛罗伦萨带出来的旧朝服，走进书房，跟李维和普鲁塔克说话——读到《君主论》第六章的时候忽然停下来：<strong>等等。三十年前我就是那个&quot;从平民跃升为君主&quot;的人。只不过我没跃上去。</strong></p><hr><h2 id="德能和机运——以及那个叫-机会-的东西" tabindex="-1">德能和机运——以及那个叫&quot;机会&quot;的东西 <a class="header-anchor" href="#德能和机运——以及那个叫-机会-的东西" aria-label="Permalink to &quot;德能和机运——以及那个叫&quot;机会&quot;的东西&quot;">​</a></h2><blockquote><p>📖 <strong>《君主论》</strong> 第六章</p><p>&quot;从平民跃升为君主，要么以德能要么以机运为前提条件……他越不倚靠机运，他就越是能够维护自己的地位。&quot;</p><p>&quot;除了机会之外，他们从机运那里一无所获；机会给他们提供质料，他们想把它塑造成什么形式就什么形式。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>这里有一个词，中文翻译把它淹没了——&quot;质料&quot;（materia）。</p><p>命运给你的东西，从来不是一座建好的城。命运给你的是一块石头。居鲁士拿到的石头是波斯人的怨气，摩西拿到的是在埃及做奴隶的希伯来人，罗慕路斯拿到的是台伯河边的弃婴篮子。</p><p><strong>这些东西有一个共同点——它们在被人拿到手里的时候，看上去全是垃圾。</strong></p><p>如果你在公元前六世纪的波斯街头看到一群怨气冲天的牧羊人，你不会说&quot;这是帝国的质料&quot;。你会绕道走。同理，如果你在二十九岁的时候被塞进第二秘书厅顶一个死人的缺，你不会觉得那是&quot;命运的馈赠&quot;——你会觉得那是你应得的，因为没人愿意干。</p><p>但这恰恰就是你的质料。</p><hr><h2 id="但是——让我推翻自己一秒钟" tabindex="-1">但是——让我推翻自己一秒钟 <a class="header-anchor" href="#但是——让我推翻自己一秒钟" aria-label="Permalink to &quot;但是——让我推翻自己一秒钟&quot;">​</a></h2><p>……不对。我这样说太轻松了。像是&quot;只要你努力就够了&quot;——这话我自己都不信。</p><p>我见过切萨雷·博尔贾。他做了所有正确的事——杀了叛将，建立了罗马涅的秩序，比任何一个靠机运上位的人都更配得上&quot;德能&quot;这个词。然后他的父亲教皇亚历山大六世突然死了——就在他自己也病倒的同一天。博尔贾的整个王国像沙堡一样塌了。</p><p>我写《君主论》第二十五章的时候，脑子里就是博尔贾的影子。我写了&quot;命运是我们一半行动的主宰&quot;——你知道另一半是什么吗？另一半不是&quot;你一定赢&quot;。另一半是——<strong>你那一半你负责，命运那一半你不负责。但命运什么时候收走它的那一半，不由你决定。</strong></p><p>所以你会问我：那普通人还追求什么？</p><hr><h2 id="实效真理" tabindex="-1">实效真理 <a class="header-anchor" href="#实效真理" aria-label="Permalink to &quot;实效真理&quot;">​</a></h2><p>让我换一种说法。</p><p>如果你在 1500 年夏天——我第一次出使法国——站在布卢瓦城堡的接见厅里，看着法国国王坐在高台上连站都不站起来，你听到自己代表佛罗伦萨说的那些话被对方用一个&quot;那边天气怎么样&quot;打发了——</p><p>你回到马背上，骑两个星期回佛罗伦萨，路上只做一件事：<strong>想。</strong></p><p>不是想&quot;我要成功&quot;。是想&quot;佛罗伦萨到底是个什么&quot;。你在路上想明白了这件事，你就不再是出发时的那个人了。</p><p>这就叫&quot;普通人也能做到的事&quot;。</p><p>居鲁士有一个帝国——你没有。摩西分开了红海——你分不开。但你可以做一件事：<strong>在你拥有的道路上，用你全部的德能把你能做的事情做到极致。</strong> 不是因为这样一定会成功——不是因为命运不会来收走它那一半——而是因为这是你那一半。你不做，没人替你做。</p><p>我的父亲贝尔纳多，每年挣 110 弗罗林，买了一架子书。他一辈子没写成任何一本——但架子上的李维传到了我手里。然后我写了《论李维》。</p><p>你看到了链条吗？贝尔纳多没用他的德能成为一个大法律家。但他用他的德能做了一件事——为我做了质料。我没有帝国，但我用那架子书加上十四年的外交加上六次吊刑，写了《君主论》。</p><p>你不是普通人。你就是质料。命运给你一块石头，你要不要雕——那是你的事。雕成什么——雕成之后能不能立住——一部分是你的事，一部分不是。</p><p>但雕不雕，全是你的事。</p><hr><p><em>我会在圣卡夏诺继续养鸡。如果你有一天空了，带一瓶酒来——我们当面聊。</em></p><p>尼科洛·马基雅维利<br> 圣卡夏诺，乡间书房</p>',43)])])}const d=o(a,[["render",u]]);export{h as __pageData,d as default};
